(function(w){"use strict";
function e(v){return String(v==null?"":v).replace(/[&<>"']/g,function(c){return {"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#39;"}[c]||c;});}
function renderField(f){var a=' data-key="'+e(f.key)+'"';if(f.raw)a+=' data-raw="1"';if(f.type==='select'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><select class="hm-calc-select"'+a+'>'+f.options.map(function(o){return '<option value="'+e(o[0])+'"'+(String(o[0])===String(f.default)?' selected':'')+'>'+e(o[1])+'</option>';}).join('')+'</select></div>';}if(f.type==='textarea'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><textarea class="hm-calc-input" rows="4"'+a+' placeholder="'+e(f.placeholder||'')+'">'+e(f.default||'')+'</textarea></div>';}var type=f.type==='date'?'date':'text';var mode=f.type==='integer'?'numeric':'decimal';return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><input class="hm-calc-input" type="'+type+'" inputmode="'+mode+'"'+a+' placeholder="'+e(f.placeholder||'')+'" value="'+e(f.default||'')+'"></div>';}
function makeRender(def){return function(root,api){var html='<div class="hm-calc-panel"><div class="hm-calc-form">';if(def.hint)html+='<p class="hm-calc-hint">'+e(def.hint)+'</p>';html+='<div class="hm-calc-grid-2">'+def.fields.map(renderField).join('')+'</div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>';root.innerHTML=html;var els=Array.prototype.slice.call(root.querySelectorAll('[data-key]')),go=root.querySelector('button'),msg=root.querySelector('.hm-calc-message'),res=root.querySelector('.hm-calc-result');go.addEventListener('click',function(){var x={};els.forEach(function(el){var k=el.getAttribute('data-key');if(el.tagName==='SELECT'||el.getAttribute('data-raw')==='1'||el.type==='date')x[k]=el.value;else x[k]=api.parseNumber(el.value);});var r=def.compute(x);if(r&&r.error){api.setMessage(msg,r.error);api.clearResult(res);return;}api.setMessage(msg,'');api.setResult(res,def.format(r,api));});};}
var defs=[{id:"roof-pitch",fields:[{"key":"rise","label":"높이 상승값","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"run","label":"수평 길이","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"높이와 수평길이는 같은 단위로 입력하세요.",compute:function(x){var a=Number(x.rise),b=Number(x.run);if(![a,b].every(Number.isFinite)||a<0||b<=0)return{error:"높이는 0 이상, 수평 길이는 0보다 크게 입력해 주세요."};var q=a/b;return{angle:Math.atan(q)*180/Math.PI,percent:q*100,slopeLength:Math.sqrt(a*a+b*b),ratio:q};},format:function(r,api){return api.resultCard("경사각",api.formatNumber(r.angle,2)+"°","")+api.resultCard("경사율",api.formatNumber(r.percent,2)+"%","")+api.resultCard("빗면 길이",api.formatNumber(r.slopeLength,3),"");}},{id:"stair-dimensions",fields:[{"key":"totalRise","label":"전체 높이 (cm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"desiredRiser","label":"목표 단높이 (cm)","type":"number","placeholder":"","default":"18","options":[],"raw":false},{"key":"treadDepth","label":"디딤판 깊이 (cm)","type":"number","placeholder":"","default":"30","options":[],"raw":false}],hint:"건축 기준과 현장 치수는 반드시 별도로 확인하세요.",compute:function(x){var h=Number(x.totalRise),r=Number(x.desiredRiser),t=Number(x.treadDepth);if(![h,r,t].every(Number.isFinite)||h<=0||r<=0||t<0)return{error:"전체 높이와 목표 단높이는 0보다 크게, 디딤판 깊이는 0 이상으로 입력해 주세요."};var steps=Math.ceil(h/r),actual=h/steps,treads=Math.max(steps-1,0);return{steps:steps,actualRiser:actual,treads:treads,totalRun:treads*t};},format:function(r,api){return api.resultCard("계단 단수",api.formatNumber(r.steps,0)+"단","")+api.resultCard("실제 단높이",api.formatNumber(r.actualRiser,2)+"cm","")+api.resultCard("총 수평길이",api.formatNumber(r.totalRun,1)+"cm","");}},{id:"pipe-volume",fields:[{"key":"innerDiameterMm","label":"내경 (mm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"lengthM","label":"길이 (m)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var d=Number(x.innerDiameterMm),l=Number(x.lengthM);if(![d,l].every(Number.isFinite)||d<0||l<0)return{error:"내경과 길이는 0 이상으로 입력해 주세요."};var dm=d/1000,m3=Math.PI*dm*dm/4*l;return{cubicMeters:m3,liters:m3*1000};},format:function(r,api){return api.resultCard("내부 용량",api.formatNumber(r.liters,3)+"L","")+api.resultCard("세제곱미터",api.formatNumber(r.cubicMeters,6)+"m³","");}},{id:"cylindrical-tank-volume",fields:[{"key":"diameterM","label":"탱크 지름 (m)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"heightM","label":"탱크 높이 (m)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"fillPercent","label":"채움률 (%)","type":"number","placeholder":"","default":"100","options":[],"raw":false}],hint:"",compute:function(x){var d=Number(x.diameterM),h=Number(x.heightM),p=Number(x.fillPercent)/100;if(![d,h,p].every(Number.isFinite)||d<0||h<0||p<0||p>1)return{error:"지름과 높이는 0 이상, 채움률은 0~100%로 입력해 주세요."};var m3=Math.PI*Math.pow(d/2,2)*h,liters=m3*1000;return{capacityLiters:liters,filledLiters:liters*p,cubicMeters:m3};},format:function(r,api){return api.resultCard("전체 용량",api.formatNumber(r.capacityLiters,2)+"L","")+api.resultCard("현재 채움량",api.formatNumber(r.filledLiters,2)+"L","")+api.resultCard("전체 부피",api.formatNumber(r.cubicMeters,4)+"m³","");}},{id:"frustum-volume",fields:[{"key":"topRadius","label":"윗면 반지름","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"bottomRadius","label":"아랫면 반지름","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"height","label":"높이","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var r=Number(x.topRadius),R=Number(x.bottomRadius),h=Number(x.height);if(![r,R,h].every(Number.isFinite)||r<0||R<0||h<0)return{error:"반지름과 높이는 0 이상으로 입력해 주세요."};var v=Math.PI*h*(R*R+R*r+r*r)/3;return{volume:v};},format:function(r,api){return api.resultCard("원뿔대 부피",api.formatNumber(r.volume,6)+" 입방단위","");}},{id:"circular-segment-area",fields:[{"key":"radius","label":"반지름","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"angleDeg","label":"중심각 (도)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var r=Number(x.radius),d=Number(x.angleDeg);if(![r,d].every(Number.isFinite)||r<0||d<0||d>360)return{error:"반지름은 0 이상, 중심각은 0~360도로 입력해 주세요."};var t=d*Math.PI/180;return{area:0.5*r*r*(t-Math.sin(t)),arc:r*t,chord:2*r*Math.sin(t/2)};},format:function(r,api){return api.resultCard("활꼴 넓이",api.formatNumber(r.area,6)+" 제곱단위","")+api.resultCard("호의 길이",api.formatNumber(r.arc,6),"")+api.resultCard("현의 길이",api.formatNumber(r.chord,6),"");}}];defs.forEach(function(def){w.HM_CALC.register(def.id,{compute:def.compute,render:makeRender(def)});});})(window);
